=== STRUCTURAL VALIDATION (local, no API needed) ===
```python
import json

def validate_workflow_definition(definition: dict) -> list[str]:
    errors = []

    # 1. Schema check
    if '$schema' not in definition:
        errors.append('Missing $schema in definition')

    # 2. Must have triggers
    triggers = definition.get('triggers', {})
    if not triggers:
        errors.append('No triggers defined — workflow needs exactly one trigger')
    elif len(triggers) > 1:
        errors.append(f'Multiple triggers defined ({len(triggers)}) — Consumption supports only one')

    # 3. Must have actions
    actions = definition.get('actions', {})
    if not actions:
        errors.append('No actions defined')

    # 4. Check runAfter references
    all_action_names = set(actions.keys())
    for name, action in actions.items():
        run_after = action.get('runAfter', {})
        for dep in run_after:
            if dep not in all_action_names:
                errors.append(f"Action '{name}' has runAfter reference to '{dep}' which does not exist")

    # 5. Check for circular dependencies
    def has_cycle(name, visited, stack):
        visited.add(name)
        stack.add(name)
        for dep in actions.get(name, {}).get('runAfter', {}):
            if dep in stack:
                return True
            if dep not in visited and has_cycle(dep, visited, stack):
                return True
        stack.discard(name)
        return False

    visited, stack = set(), set()
    for name in actions:
        if name not in visited:
            if has_cycle(name, visited, stack):
                errors.append(f'Circular dependency detected involving action: {name}')
                break

    # 6. Check connection references
    params = definition.get('parameters', {})
    conn_param = params.get('$connections', {}).get('defaultValue', {})
    # Scan action inputs for connection references
    def find_connection_refs(obj):
        refs = set()
        if isinstance(obj, str) and '@parameters' in obj and '$connections' in obj:
            # Extract connection name from @parameters('$connections')['name']
            import re
            for m in re.finditer(r"\$connections.*?\['(\w+)'\]", obj):
                refs.add(m.group(1))
        elif isinstance(obj, dict):
            for v in obj.values():
                refs.update(find_connection_refs(v))
        elif isinstance(obj, list):
            for v in obj:
                refs.update(find_connection_refs(v))
        return refs

    used_connections = find_connection_refs(actions)
    for conn in used_connections:
        if conn not in conn_param:
            errors.append(f"Connection '{conn}' referenced in actions but not in $connections parameter")

    return errors
```

=== ARM TEMPLATE VALIDATION (pre-deployment) ===
```python
def validate_arm_template(session, sub_id, rg_name, template: dict, parameters: dict = None):
    url = (
        f'https://management.azure.com/subscriptions/{sub_id}'
        f'/resourcegroups/{rg_name}'
        f'/providers/Microsoft.Resources/deployments/validate-{int(time.time())}'
        f'/validate?api-version=2022-09-01'
    )
    body = {'properties': {'mode': 'Incremental', 'template': template}}
    if parameters:
        body['properties']['parameters'] = parameters
    resp = session.post(url, json=body, timeout=(10, 60))
    if resp.status_code == 200:
        return {'valid': True, 'errors': []}
    error = resp.json().get('error', {})
    details = error.get('details', [])
    return {
        'valid': False,
        'errors': [{'code': d.get('code'), 'message': d.get('message')} for d in details] or [{'code': error.get('code'), 'message': error.get('message')}]
    }
```
